import React from 'react';
import './About.css';

const About = () => {
  return (
    <section className="about-section" id="about">
      <div className="container">
        <h2 className="section-title">About Me</h2>
        <p className="about-text">
          Hello! I'm Safaq jamal, a passionate developer with a keen interest in building responsive and visually appealing web applications. I love learning new technologies and solving real-world problems through code. When I’m not coding, you’ll find me exploring new ideas, sketching designs.
        </p>
      </div>
    </section>
  );
};

export default About;
